 35→const toCount = (value: unknown): number | null => {
 36→  const parsed = Number(value);
 37→  return Number.isFinite(parsed) && parsed >= 0 ? parsed : null;
 38→};
 39→
 40→const resolveCount = (
 41→  aggregate: Array<{count?: number}> | undefined,
 42→  fallback?: number,
 43→): number => {
 44→  return toCount(aggregate?.[0]?.count) ?? toCount(fallback) ?? 0;
 45→};
 46→
 47→const formatRelativeDate = (value: string | undefined): string => {
 48→  if (!value) return '';
 49→  const date = new Date(value);
 50→  if (Number.isNaN(date.getTime())) return value;
 51→  const now = Date.now();
 52→  const diff = now - date.getTime();
 53→  const mins = Math.floor(diff / 60000);
 54→  if (mins < 1) return 'Just now';
 55→  if (mins < 60) return `${mins}m ago`;
 56→  const hours = Math.floor(mins / 60);
 57→  if (hours < 24) return `${hours}h ago`;
 58→  const days = Math.floor(hours / 24);
 59→  if (days < 7) return `${days}d ago`;
 60→  return date.toLocaleDateString(undefined, {month: 'short', day: 'numeric', year: 'numeric'});
 61→};
 62→
 63→const extractBannerImage = (content: string | null | undefined): string | null => {
 64→  if (!content) return null;
 65→  try {
 66→    const parsed = JSON.parse(content);
 67→    const findImage = (node: any): string | null => {
 68→      if (node.type === 'image' && node.src) return node.src;
 69→      if (node.children) {
 70→        for (const child of node.children) {
 71→          const found = findImage(child);
 72→          if (found) return found;
 73→        }
 74→      }
 75→      return null;
 76→    };
 77→    return findImage(parsed.root ?? parsed);
 78→  } catch {
 79→    return null;
 80→  }
 81→};
 82→
 83→type CommentThreadProps = {
 84→  comment: JournalComment;
 85→  postId: string;
 86→  isLoggedIn: boolean;
 87→  onReply: (commentId: string, userName: string) => void;
 88→  onToggleReplies: (commentId: string) => void;
 89→  expandedReplies: Set<string>;
 90→  colors: Palette;
 91→  depth: number;
 92→};
 93→
 94→function CommentThread({
 95→  comment,
 96→  postId,
 97→  isLoggedIn,
 98→  onReply,
 99→  onToggleReplies,
100→  expandedReplies,
101→  colors,
102→  depth,
103→}: CommentThreadProps) {
104→  const isExpanded = expandedReplies.has(comment.id);
105→  const repliesQuery = useQuery({
106→    queryKey: ['comment-replies', comment.id],
107→    queryFn: () => socialApi.getReplies(postId, comment.id),
108→    enabled: isExpanded,
109→  });
110→
111→  const replies = repliesQuery.data?.comments ?? [];
112→  const replyCount = comment.reply_count ?? 0;
113→  const userName = comment.users?.name || 'User';
114→
115→  const avatarSize = depth === 0 ? 28 : 24;
116→  const bodyPaddingLeft = depth === 0 ? 36 : 32;
117→  const repliesMarginLeft = depth === 0 ? 36 : 24;
118→
119→  return (
120→    <View>
121→      <View style={[styles.commentCard, {borderTopColor: colors.borderCard}]}>
122→        <View style={styles.commentHeader}>
123→          <Avatar
124→            uri={(comment.users as any)?.image_url}
125→            name={comment.users?.name}
126→            size={avatarSize}
127→          />
128→          <View style={styles.commentMeta}>
129→            <Text style={[styles.commentAuthor, {color: colors.textPrimary}]}>
130→              {userName}
131→            </Text>
132→            <Text style={[styles.commentTime, {color: colors.textFaint}]}>
133→              {formatRelativeDate(comment.created_at)}
134→            </Text>
135→          </View>
136→        </View>
137→        <Text style={[styles.commentBody, {color: colors.textSecondary, paddingLeft: bodyPaddingLeft}]}>
138→          {comment.comment || ''}
139→        </Text>
140→        <View style={[styles.commentActions, {paddingLeft: bodyPaddingLeft}]}>
141→          {isLoggedIn && (
142→            <Pressable
143→              style={styles.actionButton}
144→              onPress={() => onReply(comment.id, userName)}>
145→              <ReplyIcon size={14} color={colors.textMuted} />
146→              <Text style={[styles.actionText, {color: colors.textMuted}]}>
147→                Reply
148→              </Text>
149→            </Pressable>
150→          )}
151→          {replyCount > 0 && (
152→            <Pressable
153→              style={styles.actionButton}
154→              onPress={() => onToggleReplies(comment.id)}>
155→              <Text style={[styles.actionText, {color: colors.accentGold}]}>
156→                {isExpanded ? 'Hide replies' : `Show ${replyCount} ${replyCount === 1 ? 'reply' : 'replies'}`}
157→              </Text>
158→            </Pressable>
159→          )}
160→        </View>
161→      </View>
162→
163→      {isExpanded && (
164→        <View style={[styles.repliesContainer, {borderLeftColor: colors.borderLight, marginLeft: repliesMarginLeft}]}>
165→          {repliesQuery.isLoading ? (
166→            <View style={styles.repliesLoading}>
167→              <ActivityIndicator size="small" color={colors.loaderColor} />
168→            </View>
169→          ) : repliesQuery.isError ? (
170→            <Text style={[styles.repliesError, {color: colors.danger}]}>
171→              Failed to load replies.
172→            </Text>
173→          ) : (
174→            replies.map(reply => (
175→              <CommentThread
176→                key={reply.id}
177→                comment={reply}
178→                postId={postId}
179→                isLoggedIn={isLoggedIn}
180→                onReply={onReply}
181→                onToggleReplies={onToggleReplies}
182→                expandedReplies={expandedReplies}
183→                colors={colors}
184→                depth={depth + 1}
185→              />
186→            ))
187→          )}
188→        </View>
189→      )}
190→    </View>
191→  );
192→}
