194→export function PostDetailScreen({route}: Props) {
195→  const {user, session} = useAuth();
196→  const {colors} = useTheme();
197→  const {journalId} = route.params;
198→  const token = session?.access_token ?? '';
199→  const [commentInput, setCommentInput] = useState('');
200→  const [repostCaption, setRepostCaption] = useState('');
201→  const [showRepost, setShowRepost] = useState(false);
202→  const [replyingTo, setReplyingTo] = useState<{id: string; userName: string} | null>(null);
203→  const [expandedReplies, setExpandedReplies] = useState<Set<string>>(new Set());
204→  const scrollViewRef = useRef<ScrollView>(null);
205→  const inputRef = useRef<TextInput>(null);
206→
207→  const handleReply = useCallback((commentId: string, userName: string) => {
208→    setReplyingTo({id: commentId, userName});
209→    setTimeout(() => {
210→      inputRef.current?.focus();
211→      scrollViewRef.current?.scrollToEnd({animated: true});
212→    }, 100);
213→  }, []);
214→
215→  const handleToggleReplies = useCallback((commentId: string) => {
216→    setExpandedReplies(prev => {
217→      const next = new Set(prev);
218→      if (next.has(commentId)) {
219→        next.delete(commentId);
220→      } else {
221→        next.add(commentId);
222→      }
223→      return next;
224→    });
225→  }, []);
226→
227→  const detailQuery = useQuery({
228→    queryKey: ['journal', journalId, user?.id],
229→    queryFn: () => mobileApi.getJournalById(journalId, user?.id),
230→  });
231→
232→  const commentsQuery = useQuery({
233→    queryKey: ['journal-comments', journalId],
234→    queryFn: () => socialApi.getComments(journalId, null, 20),
235→  });
236→
237→  const reactionMutation = useMutation({
238→    mutationFn: async (reactionType: string) => {
239→      const journal = detailQuery.data?.journal;
240→      const receiverId = journal?.user_id ?? journal?.users?.id;
241→      if (!token) throw new Error('Please log in to react.');
242→      if (!journal?.id || !receiverId) throw new Error('Missing journal data.');
243→      return socialApi.toggleReaction(token, {
244→        journalId: journal.id,
245→        receiverId,
246→        reactionType,
247→      });
248→    },
249→    onSuccess: () => {
250→      queryClient.invalidateQueries({queryKey: ['journal', journalId]});
251→      queryClient.invalidateQueries({queryKey: ['feed']});
252→    },
253→    onError: e => Alert.alert('Reaction failed', e instanceof Error ? e.message : 'Error'),
254→  });
255→
256→  const bookmarkMutation = useMutation({
257→    mutationFn: async () => {
258→      if (!token) throw new Error('Please log in to bookmark.');
259→      return socialApi.toggleBookmark(token, {journalId});
260→    },
261→    onSuccess: () => {
262→      queryClient.invalidateQueries({queryKey: ['journal', journalId]});
263→      queryClient.invalidateQueries({queryKey: ['feed']});
264→    },
265→    onError: e => Alert.alert('Bookmark failed', e instanceof Error ? e.message : 'Error'),
266→  });
267→
268→  const addCommentMutation = useMutation({
269→    mutationFn: async () => {
270→      const body = commentInput.trim();
271→      const receiverId = detailQuery.data?.journal?.user_id ?? detailQuery.data?.journal?.users?.id;
272→      if (!token) throw new Error('Please log in to comment.');
273→      if (!body) throw new Error('Comment cannot be empty.');
274→      if (!receiverId) throw new Error('Missing journal owner.');
275→      return socialApi.addComment(token, {
276→        comments: body,
277→        postId: journalId,
278→        receiverId,
279→        parentId: replyingTo?.id,
280→      });
281→    },
282→    onSuccess: () => {
283→      const parentId = replyingTo?.id;
284→      setCommentInput('');
285→      setReplyingTo(null);
286→      queryClient.invalidateQueries({queryKey: ['journal-comments', journalId]});
287→      queryClient.invalidateQueries({queryKey: ['journal', journalId]});
288→      if (parentId) {
289→        queryClient.invalidateQueries({queryKey: ['comment-replies', parentId]});
290→      }
291→    },
292→    onError: e => Alert.alert('Comment failed', e instanceof Error ? e.message : 'Error'),
293→  });
294→
295→  const repostMutation = useMutation({
296→    mutationFn: async () => {
297→      if (!token) throw new Error('Please log in to repost.');
298→      return socialApi.createRepost(token, {
299→        sourceJournalId: journalId,
300→        caption: repostCaption.trim() || undefined,
301→      });
302→    },
303→    onSuccess: () => {
304→      setRepostCaption('');
305→      setShowRepost(false);
306→      Alert.alert('Reposted', 'Post was reposted to your feed.');
307→      queryClient.invalidateQueries({queryKey: ['feed']});
308→    },
309→    onError: e => Alert.alert('Repost failed', e instanceof Error ? e.message : 'Error'),
310→  });
311→
312→  const journal = detailQuery.data?.journal;
313→  const likeCount = resolveCount(journal?.like_count, journal?.likes_count);
314→  const commentCount = resolveCount(journal?.comment_count, journal?.comments_count);
315→  const bookmarkCount = resolveCount(journal?.bookmark_count);
316→  const comments = commentsQuery.data?.comments ?? [];
317→  const bannerImage = useMemo(() => extractBannerImage(journal?.content), [journal?.content]);
318→
319→  if (detailQuery.isLoading) {
320→    return (
321→      <SafeAreaView style={[styles.safe, {backgroundColor: colors.bgPrimary}]}>
322→        <View style={styles.loadingContainer}>
323→          <SkeletonLoader height={200} borderRadius={0} />
324→          <View style={styles.contentPadding}>
325→            <SkeletonLoader width="70%" height={24} />
326→            <SkeletonLoader width="40%" height={16} style={{marginTop: 12}} />
327→            <SkeletonLoader width="100%" height={16} style={{marginTop: 20}} />
328→            <SkeletonLoader width="100%" height={16} style={{marginTop: 8}} />
329→            <SkeletonLoader width="60%" height={16} style={{marginTop: 8}} />
330→          </View>
331→        </View>
332→      </SafeAreaView>
333→    );
334→  }
335→
336→  if (detailQuery.isError) {
337→    return (
338→      <SafeAreaView style={[styles.safe, {backgroundColor: colors.bgPrimary}]}>
339→        <View style={styles.contentPadding}>
340→          <Text style={[styles.errorText, {color: colors.danger}]}>
341→            Unable to load this post.
342→          </Text>
343→        </View>
344→      </SafeAreaView>
345→    );
346→  }
347→
348→  return (
349→    <ScrollView
350→      ref={scrollViewRef}
351→      style={[styles.scroll, {backgroundColor: colors.bgPrimary}]}
352→      showsVerticalScrollIndicator={false}>
353→      {/* Banner image */}
354→      {bannerImage && (
355→        <Image source={{uri: bannerImage}} style={styles.banner} resizeMode="cover" />
356→      )}
357→
358→      <View style={styles.contentPadding}>
359→        {/* Title */}
360→        <Text style={[styles.title, {color: colors.textHeading}]}>
361→          {journal?.title || 'Untitled Post'}
362→        </Text>
363→
364→        {/* Author section */}
365→        <View style={styles.authorRow}>
366→          <Avatar
367→            uri={journal?.users?.image_url}
368→            name={journal?.users?.name}
369→            size={36}
370→            badge={journal?.users?.badge as 'legend' | 'og' | undefined}
371→          />
372→          <View style={styles.authorInfo}>
373→            <View style={styles.authorNameRow}>
374→              <Text style={[styles.authorName, {color: colors.textPrimary}]}>
375→                {journal?.users?.name || 'Unknown author'}
376→              </Text>
377→              {journal?.users?.badge ? (
378→                <BadgeCheckIcon size={16} badge={journal.users.badge as 'legend' | 'og'} />
379→              ) : null}
380→            </View>
381→            <Text style={[styles.dateText, {color: colors.textMuted}]}>
382→              {formatRelativeDate(journal?.created_at)}
383→            </Text>
384→          </View>
385→        </View>
386→
387→        {/* Action bar */}
388→        <ActionBar
389→          likeCount={likeCount}
390→          commentCount={commentCount}
391→          bookmarkCount={bookmarkCount}
392→          isLiked={journal?.has_liked}
393→          isBookmarked={journal?.has_bookmarked}
394→          userReaction={journal?.user_reaction}
395→          onReact={type => reactionMutation.mutate(type)}
396→          onComment={() => {/* scroll to comments */}}
397→          onBookmark={() => bookmarkMutation.mutate()}
398→          onRepost={() => setShowRepost(!showRepost)}
399→        />
400→
401→        {/* Repost section */}
402→        {showRepost && (
403→          <View style={[styles.repostSection, {backgroundColor: colors.bgSecondary, borderColor: colors.borderLight}]}>
404→            <TextInput
405→              value={repostCaption}
406→              onChangeText={setRepostCaption}
407→              placeholder="Add an optional caption"
408→              placeholderTextColor={colors.textFaint}
409→              style={[styles.commentInput, {backgroundColor: colors.bgElevated, borderColor: colors.borderCard, color: colors.textPrimary}]}
410→              maxLength={280}
411→              multiline
412→            />
413→            <PrimaryButton
414→              label={repostMutation.isPending ? 'Reposting...' : 'Repost to feed'}
415→              onPress={() => repostMutation.mutate()}
416→              disabled={repostMutation.isPending}
417→            />
418→          </View>
419→        )}
420→
421→        {/* Divider */}
422→        <View style={[styles.divider, {backgroundColor: colors.borderLight}]} />
423→
424→        {/* Content body */}
425→        <LexicalRenderer content={journal?.content} />
426→
427→        {/* Related posts */}
428→        <RelatedPosts journalId={journalId} />
429→
430→        {/* Divider */}
431→        <View style={[styles.divider, {backgroundColor: colors.borderLight}]} />
432→
433→        {/* Comments section */}
434→        <Text style={[styles.sectionTitle, {color: colors.textHeading}]}>
435→          Comments ({commentCount})
436→        </Text>
437→
438→        {commentsQuery.isLoading ? (
439→          <View style={styles.commentLoading}>
440→            <ActivityIndicator color={colors.loaderColor} />
441→          </View>
442→        ) : comments.filter(c => !c.parent_id).length === 0 ? (
443→          <Text style={[styles.noComments, {color: colors.textMuted}]}>
444→            No comments yet. Be the first!
445→          </Text>
446→        ) : (
447→          comments
448→            .filter(c => !c.parent_id)
449→            .map(comment => (
450→              <CommentThread
451→                key={comment.id}
452→                comment={comment}
453→                postId={journalId}
454→                isLoggedIn={!!token}
455→                onReply={handleReply}
456→                onToggleReplies={handleToggleReplies}
457→                expandedReplies={expandedReplies}
458→                colors={colors}
459→                depth={0}
460→              />
461→            ))
462→        )}
463→
464→        {/* Comment input */}
465→        {token ? (
466→          <View style={styles.commentInputRow}>
467→            {replyingTo && (
468→              <View style={[styles.replyBanner, {backgroundColor: colors.bgSecondary}]}>
469→                <Text style={[styles.replyBannerText, {color: colors.textPrimary}]}>
470→                  Replying to {replyingTo.userName}
471→                </Text>
472→                <Pressable onPress={() => setReplyingTo(null)} hitSlop={8}>
473→                  <XIcon size={16} color={colors.textMuted} />
474→                </Pressable>
475→              </View>
476→            )}
477→            <TextInput
478→              ref={inputRef}
479→              value={commentInput}
480→              onChangeText={setCommentInput}
481→              placeholder={replyingTo ? `Reply to ${replyingTo.userName}...` : 'Write a comment...'}
482→              placeholderTextColor={colors.textFaint}
483→              style={[
484→                styles.commentInput,
485→                {
486→                  backgroundColor: colors.bgSecondary,
487→                  borderColor: colors.borderCard,
488→                  color: colors.textPrimary,
489→                },
490→              ]}
491→              maxLength={200}
492→              multiline
493→            />
494→            <PrimaryButton
495→              label={addCommentMutation.isPending ? 'Posting...' : 'Post'}
496→              onPress={() => addCommentMutation.mutate()}
497→              disabled={commentInput.trim().length === 0 || addCommentMutation.isPending}
498→            />
499→          </View>
500→        ) : null}
501→
502→        <View style={styles.bottomSpacer} />
503→      </View>
504→    </ScrollView>
505→  );
506→}
